-- Check total count
SELECT 'Total Questions' as label, COUNT(*) as count FROM questions_answers;

-- Check count per unit
SELECT unit_id, unit_name, COUNT(*) as count 
FROM questions_answers 
GROUP BY unit_id, unit_name 
ORDER BY unit_id;

